func:
var dist = msg.payload.dist;
var angle = msg.payload.angle;

if (dist > 40) dist = 40;

if (dist < 40) {
    msg.payload.status = "OBSTACLE DETECTE !";
} else {
    msg.payload.status = "Libre";
}

msg.payload.dist = dist;
var chartMsg = { payload: dist };

var count = context.get('count') || 0;
if (dist < 40) {
    count++;
    context.set('count', count);
    msg.payload.count = count;
}

if (dist < 40) {
    msg.payload.heure = new Date().toLocaleTimeString();
}

var telegramMsg = { payload: dist };

return [msg, chartMsg, telegramMsg];
